apiVersion: policies.kyverno.io/v1
kind: MutatingPolicy
metadata:
  name: add-default-resources
  annotations:
    policies.kyverno.io/title: Add Default Resources
    policies.kyverno.io/category: Other
    policies.kyverno.io/severity: medium
    policies.kyverno.io/subject: Pod
    policies.kyverno.io/minversion: 1.16.0
    policies.kyverno.io/description: >-
      Pods which don't specify at least resource requests are assigned a QoS class
      of BestEffort which can hog resources for other Pods on Nodes. At a minimum,
      all Pods should specify resource requests in order to be labeled as the QoS
      class Burstable. This policy mutates any container in a Pod which doesn't
      specify memory or cpu requests to apply some sane defaults.
spec:
  matchConstraints:
    resourceRules:
      - apiGroups:   [""]
        apiVersions: ["v1"]
        resources:   ["pods"]
        operations:  ["CREATE", "UPDATE"]

  # background: false from the original ClusterPolicy is expressed here:
  # admission is enabled (default), mutateExisting (background scan) is disabled.
  evaluation:
    admission:
      enabled: true
    mutateExisting:
      enabled: false

  mutations:
    # Mutate regular containers — always present on a Pod.
    - patchType: ApplyConfiguration
      applyConfiguration:
        expression: |
          Object{
            spec: Object.spec{
              containers: object.spec.containers.map(c, Object.spec.containers{
                name: c.name,
                resources: Object.spec.containers.resources{
                  requests: Object.spec.containers.resources.requests{
                    cpu: has(c.resources) && has(c.resources.requests) && has(c.resources.requests.cpu)
                         ? c.resources.requests.cpu
                         : "100m",
                    memory: has(c.resources) && has(c.resources.requests) && has(c.resources.requests.memory)
                            ? c.resources.requests.memory
                            : "100Mi"
                  }
                }
              })
            }
          }

    # Mutate init containers — optional field, guarded with has() before iterating.
    - patchType: ApplyConfiguration
      applyConfiguration:
        expression: |
          has(object.spec.initContainers) && object.spec.initContainers.size() > 0
          ? Object{
              spec: Object.spec{
                initContainers: object.spec.initContainers.map(c, Object.spec.initContainers{
                  name: c.name,
                  resources: Object.spec.initContainers.resources{
                    requests: Object.spec.initContainers.resources.requests{
                      cpu: has(c.resources) && has(c.resources.requests) && has(c.resources.requests.cpu)
                           ? c.resources.requests.cpu
                           : "100m",
                      memory: has(c.resources) && has(c.resources.requests) && has(c.resources.requests.memory)
                              ? c.resources.requests.memory
                              : "100Mi"
                    }
                  }
                })
              }
            }
          : Object{}

    # Mutate ephemeral containers — optional field, guarded with has() before iterating.
    - patchType: ApplyConfiguration
      applyConfiguration:
        expression: |
          has(object.spec.ephemeralContainers) && object.spec.ephemeralContainers.size() > 0
          ? Object{
              spec: Object.spec{
                ephemeralContainers: object.spec.ephemeralContainers.map(c, Object.spec.ephemeralContainers{
                  name: c.name,
                  resources: Object.spec.ephemeralContainers.resources{
                    requests: Object.spec.ephemeralContainers.resources.requests{
                      cpu: has(c.resources) && has(c.resources.requests) && has(c.resources.requests.cpu)
                           ? c.resources.requests.cpu
                           : "100m",
                      memory: has(c.resources) && has(c.resources.requests) && has(c.resources.requests.memory)
                              ? c.resources.requests.memory
                              : "100Mi"
                    }
                  }
                })
              }
            }
          : Object{}

