apiVersion: policies.kyverno.io/v1
kind: MutatingPolicy
metadata:
  annotations:
    policies.kyverno.io/category: Other
    policies.kyverno.io/description: "Pods which don't specify at least resource requests are assigned a QoS class of BestEffort which can hog resources for other Pods on Nodes. At a minimum, all Pods should specify resource requests in order to be labeled as the QoS class Burstable. This sample mutates any container in a Pod which doesn't specify memory or cpu requests to apply some sane defaults."
    policies.kyverno.io/minversion: 1.17.0
    policies.kyverno.io/severity: medium
    policies.kyverno.io/subject: Pod
    policies.kyverno.io/title: Add Default Resources
  name: add-default-resources
spec:
  matchConditions:
    - expression: |-
        object.spec.containers.exists(c, !has(c.resources) || !has(c.resources.requests) || !has(c.resources.requests.memory) || !has(c.resources.requests.cpu)) ||
        (has(object.spec.initContainers) && object.spec.initContainers.exists(c, !has(c.resources) || !has(c.resources.requests) || !has(c.resources.requests.memory) || !has(c.resources.requests.cpu))) ||
        (has(object.spec.ephemeralContainers) && object.spec.ephemeralContainers.exists(c, !has(c.resources) || !has(c.resources.requests) || !has(c.resources.requests.memory) || !has(c.resources.requests.cpu)))
      name: has-container-missing-requests
  matchConstraints:
    resourceRules:
      - apiGroups:
          - ""
        apiVersions:
          - v1
        operations:
          - CREATE
          - UPDATE
        resources:
          - pods
  mutations:
    - applyConfiguration:
        expression: |-
          Object{
            spec: Object.spec{
              containers: object.spec.containers.map(c, Object.spec.containers{
                name: c.name,
                resources: Object.spec.containers.resources{
                  requests: Object.spec.containers.resources.requests{
                    memory: (!has(c.resources) || !has(c.resources.requests) || !has(c.resources.requests.memory)) ? "100Mi" : c.resources.requests.memory,
                    cpu: (!has(c.resources) || !has(c.resources.requests) || !has(c.resources.requests.cpu)) ? "100m" : c.resources.requests.cpu
                  }
                }
              }),
              initContainers: has(object.spec.initContainers) ? object.spec.initContainers.map(c, Object.spec.initContainers{
                name: c.name,
                resources: Object.spec.initContainers.resources{
                  requests: Object.spec.initContainers.resources.requests{
                    memory: (!has(c.resources) || !has(c.resources.requests) || !has(c.resources.requests.memory)) ? "100Mi" : c.resources.requests.memory,
                    cpu: (!has(c.resources) || !has(c.resources.requests) || !has(c.resources.requests.cpu)) ? "100m" : c.resources.requests.cpu
                  }
                }
              }) : object.spec.?initContainers.orValue([]),
              ephemeralContainers: has(object.spec.ephemeralContainers) ? object.spec.ephemeralContainers.map(c, Object.spec.ephemeralContainers{
                name: c.name,
                resources: Object.spec.ephemeralContainers.resources{
                  requests: Object.spec.ephemeralContainers.resources.requests{
                    memory: (!has(c.resources) || !has(c.resources.requests) || !has(c.resources.requests.memory)) ? "100Mi" : c.resources.requests.memory,
                    cpu: (!has(c.resources) || !has(c.resources.requests) || !has(c.resources.requests.cpu)) ? "100m" : c.resources.requests.cpu
                  }
                }
              }) : object.spec.?ephemeralContainers.orValue([])
            }
          }
      patchType: ApplyConfiguration

