          },
          {
            "expression": "object.spec.?volumes.orValue([]).all(vol, !has(vol.hostPath) || vol.hostPath.path != '/var/run/crio/crio.sock')",
            "message": "Use of CRI-O socket bind mount (/var/run/crio/crio.sock) is not allowed."
          },
          {
            "expression": "object.spec.?volumes.orValue([]).all(vol, !has(vol.hostPath) || vol.hostPath.path != '/var/run/cri-dockerd.sock')",
            "message": "Use of Docker CRI socket bind mount (/var/run/cri-dockerd.sock) is not allowed."
          }
        ]
