apiVersion: policies.kyverno.io/v1
kind: MutatingPolicy
metadata:
  annotations:
    policies.kyverno.io/category: Sample
    policies.kyverno.io/description: 'The sidecar pattern is very common in Kubernetes whereby other applications can insert components via tacit modification of a submitted resource. This is, for example, often how service meshes and secrets applications are able to function transparently. This policy injects a sidecar container, initContainer, and volume into Pods that match an annotation called `vault.hashicorp.com/agent-inject: true`.'
    policies.kyverno.io/minversion: 1.6.0
    policies.kyverno.io/subject: Deployment,Volume
    policies.kyverno.io/title: Inject Sidecar Container
  name: inject-sidecar
spec:
  matchConditions:
    - expression: "object.spec.template.metadata.?annotations[?'vault.hashicorp.com/agent-inject'].orValue('') == 'true'"
      name: has-vault-inject-annotation
  matchConstraints:
    resourceRules:
      - apiGroups:
          - apps
        apiVersions:
          - v1
        operations:
          - CREATE
          - UPDATE
        resources:
          - deployments
  mutations:
    - applyConfiguration:
        expression: |-
          Object{
            spec: Object.spec{
              template: Object.spec.template{
                spec: Object.spec.template.spec{
                  containers: [
                    Object.spec.template.spec.containers{
                      name: "vault-agent",
                      image: "vault:1.5.4",
                      imagePullPolicy: "IfNotPresent",
                      volumeMounts: [
                        Object.spec.template.spec.containers.volumeMounts{
                          mountPath: "/vault/secrets",
                          name: "vault-secret"
                        }
                      ]
                    }
                  ] + object.spec.template.spec.containers,
                  initContainers: [
                    Object.spec.template.spec.initContainers{
                      name: "vault-agent-init",
                      image: "vault:1.5.4",
                      imagePullPolicy: "IfNotPresent",
                      volumeMounts: [
                        Object.spec.template.spec.initContainers.volumeMounts{
                          mountPath: "/vault/secrets",
                          name: "vault-secret"
                        }
                      ]
                    }
                  ] + object.spec.template.spec.?initContainers.orValue([]),
                  volumes: [
                    Object.spec.template.spec.volumes{
                      name: "vault-secret",
                      emptyDir: Object.spec.template.spec.volumes.emptyDir{
                        medium: "Memory"
                      }
                    }
                  ] + object.spec.template.spec.?volumes.orValue([])
                }
              }
            }
          }
      patchType: ApplyConfiguration

