Look up Kyverno 1.17+ documentation and examples before writing the policy:
- https://kyverno.io/docs/
- https://github.com/kyverno/kyverno-policies


  I'll start by loading the relevant skills and reading the existing policy, then look up the documentation.


  Now let me load the ClusterPolicy sub-skill and check for any existing output directory:


  Now let me look up Kyverno 1.17+ ValidatingPolicy documentation and examples for API calls in CEL-based policies.


  Now I'll create the requirements.md and then generate the converted ValidatingPolicy.


  Now I'll generate the ValidatingPolicy using the generate_policy tool with the requirements:



    {
      "apiVersion": "policies.kyverno.io/v1",
      "kind": "ValidatingPolicy",
      "metadata": {
        "name": "pdb-minavailable-check",
        "annotations": {
          "policies.kyverno.io/title": "Check PodDisruptionBudget minAvailable",
          "policies.kyverno.io/category": "Other",
          "policies.kyverno.io/severity": "medium",
          "policies.kyverno.io/minversion": "1.17.0",
          "policies.kyverno.io/subject": "PodDisruptionBudget, Deployment, StatefulSet",
          "policies.kyverno.io/description": "When a Pod controller which can run multiple replicas is subject to an active PodDisruptionBudget, if the replicas field has a value equal to the minAvailable value of the PodDisruptionBudget it may prevent voluntary disruptions including Node drains which may impact routine maintenance tasks and disrupt operations. This policy checks incoming Deployments and StatefulSets which have a matching PodDisruptionBudget to ensure these two values do not match."
        }
      },
      "spec": {
        "autogen": {
          "podControllers": {
            "controllers": []
          }
        },
        "evaluation": {
          "background": {
            "enabled": false
          }
        },
        "matchConstraints": {
          "resourceRules": [
            {
              "apiGroups": ["apps"],
              "apiVersions": ["v1"],
              "operations": ["CREATE", "UPDATE"],
              "resources": ["deployments", "statefulsets"]
            }
          ]
        },
        "matchConditions": [
          {
            "name": "has-replicas",
            "expression": "object.spec.?replicas.orValue(1) > 0"
          }
        ],
        "validationActions": ["Audit"],
        "variables": [
          {
            "name": "pdbs",
            "expression": "resource.List('policy/v1', 'poddisruptionbudgets', request.namespace).items.orValue([])"
          },
          {
            "name": "podTemplateLabels",
            "expression": "object.spec.template.?metadata.?labels.orValue({})"
          },
          {
            "name": "matchingPdbs",
            "expression": "variables.pdbs.filter(pdb, pdb.spec.?selector.?matchLabels.orValue({}).all(k, k in variables.podTemplateLabels && variables.podTemplateLabels[k] == pdb.spec.selector.matchLabels[k]))"
          },
          {
            "name": "matchedMinAvailable",
            "expression": "size(variables.matchingPdbs) > 0 ? variables.matchingPdbs[0].spec.?minAvailable.orValue(0) : 0"
          }
        ],
        "validations": [
          {
            "expression": "!(object.spec.?replicas.orValue(1) == variables.matchedMinAvailable && variables.matchedMinAvailable > 0)",
            "message": "The matching PodDisruptionBudget for this resource has its minAvailable value equal to the replica count which is not permitted."
          }
        ]
      }
    }



